parameters.jsonBody:
={{ {
  "contents": [{
    "parts": [{
      "text": "Write a personalized Google review request message for a customer of Manivtha Tours & Travels.

--- DETAILS ---
Customer: " + ($json.body.customerName || "Valued Customer") + "
Trip: " + ($json.body.tripType || "Tour") + "
Destination: " + ($json.body.destination || "their destination") + "
Date: " + ($json.body.travelDate || "recently") + "
Driver: " + ($json.body.driverName || "our driver") + "
Notes: " + ($json.body.experienceNotes || "None") + "
Instructions: " + ($json.body.specialInstructions || "None") + "
Link: " + ($json.body.reviewLink || "") + "

--- RULES ---
1. Write a maximum of 120 words.
2. The tone must be " + ($json.body.tone || "Friendly") + ".
3. Mention the trip details naturally.
4. Thank the customer and ask for a review politely.
5. Sign off as 'The Manivtha Tours & Travels Team'.
6. DO NOT include any placeholders or brackets.

Please provide ONLY the final message."
    }]
  }],
  "generationConfig": {
    "temperature": 0.7,
    "maxOutputTokens": 250
  }
} }}
